const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const prompt = String(body.prompt ?? '').trim();
if (!prompt) {
  throw new Error('Missing prompt');
}
const negativePrompt = String(body.negativePrompt ?? body.negative_prompt ?? '').trim();
const mode = String(body.mode ?? 'text-to-image');
const model = String(body.model ?? 'gpt-5.5').trim() || 'gpt-5.5';
const systemPrompt = [
  'You are a senior image prompt engineer.',
  'Rewrite user prompts for text-to-image and image-to-image generation.',
  'Output concise, detailed, production-ready prompts.',
  'Keep safety-compliant language and avoid policy-violating requests.',
  'Return plain text only without markdown.'
].join(' ');
const userPrompt = [
  'Task: optimize image generation prompt.',
  'Mode: ' + mode,
  'Original Prompt: ' + prompt,
  negativePrompt ? 'Negative Prompt: ' + negativePrompt : ''
].filter(Boolean).join('\n');
return [{
  json: {
    requestPayload: {
      model,
      stream: false,
      input: [
        {
          role: 'system',
          content: [{ type: 'input_text', text: systemPrompt }],
        },
        {
          role: 'user',
          content: [{ type: 'input_text', text: userPrompt }],
        },
      ],
    },
    originalPrompt: prompt,
    originalNegativePrompt: negativePrompt,
    mode,
    model,
  },
}];

const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

if (payload && typeof payload === 'object') {
  const upstreamError = payload.error || payload.errors || null;
  if (upstreamError) {
    const message = typeof upstreamError === 'string'
      ? upstreamError
      : typeof payload.message === 'string'
        ? payload.message
        : typeof upstreamError.message === 'string'
          ? upstreamError.message
          : JSON.stringify(upstreamError).slice(0, 2000);
    return [{
      json: {
        ok: false,
        status: 'upstream_error',
        message,
        raw: payload,
      },
    }];
  }
}

const candidates = [];
const seen = new Set();
const pushCandidate = (value) => {
  if (typeof value !== 'string') return;
  const text = value.trim();
  if (!text) return;
  if (seen.has(text)) return;
  seen.add(text);
  candidates.push(text);
};

if (Array.isArray(payload.output)) {
  for (const item of payload.output) {
    if (!item || typeof item !== 'object') continue;
    if (!Array.isArray(item.content)) continue;
    for (const part of item.content) {
      if (!part || typeof part !== 'object') continue;
      if (part.type === 'output_text') {
        pushCandidate(part.text);
      }
    }
  }
}

if (typeof payload.output_text === 'string') {
  pushCandidate(payload.output_text);
} else if (Array.isArray(payload.output_text)) {
  for (const chunk of payload.output_text) {
    if (typeof chunk === 'string') {
      pushCandidate(chunk);
      continue;
    }
    if (chunk && typeof chunk === 'object') {
      pushCandidate(chunk.text);
    }
  }
}

const walk = (node, path = '') => {
  if (!node) return;

  if (Array.isArray(node)) {
    node.forEach((item, index) => walk(item, `${path}[${index}]`));
    return;
  }

  if (typeof node !== 'object') return;

  if (typeof node.text === 'string') {
    const type = typeof node.type === 'string' ? node.type : '';
    if (type === 'output_text' || /content|message|choice|result|response/i.test(path)) {
      pushCandidate(node.text);
    }
  }

  if (typeof node.output_text === 'string') {
    pushCandidate(node.output_text);
  }

  const allowedKeys = new Set([
    'output',
    'content',
    'message',
    'messages',
    'choices',
    'parts',
    'data',
    'result',
    'response',
    'items',
    'tool_outputs',
    'output_text',
  ]);

  for (const [key, value] of Object.entries(node)) {
    if (!allowedKeys.has(key)) continue;
    walk(value, path ? `${path}.${key}` : key);
  }
};

if (candidates.length === 0) {
  walk(payload);
}

const optimizedPrompt = (candidates.find((text) => text.length > 8) || candidates[0] || '').slice(0, 6000).trim();
if (!optimizedPrompt) {
  throw new Error('Responses API returned no optimization text.');
}

return [{
  json: {
    ok: true,
    optimizedPrompt,
    summary: optimizedPrompt.slice(0, 500),
    raw: payload,
  },
}];
